css:
.ps-wiki-drawer-trigger { display: none; padding: var(--pds-space-1); background: transparent; border: none; cursor: pointer; color: var(--pds-text-primary); }
@media (max-width: 799px) { .ps-wiki-drawer-trigger { display: flex; } }
.ps-wiki-drawer-backdrop { position: fixed; inset: 0; background: rgba(0,0,0,0.5); z-index: 100; }
.ps-wiki-drawer-backdrop[hidden] { display: none; }
.ps-wiki-drawer { position: fixed; inset-block: 0; inset-inline-start: 0; width: min(80vw, 20rem); background: var(--pds-surface-layer); border-inline-end: 1px solid var(--pds-border-subtle); padding: var(--pds-space-2); z-index: 101; overflow-y: auto; transform: translateX(-100%); transition: transform var(--pds-duration-slow) var(--pds-easing-decelerate); }
.ps-wiki-drawer:not([hidden]) { transform: translateX(0); }
.ps-wiki-drawer__list { list-style: none; padding: 0; }
.ps-wiki-drawer__link { display: block; padding: var(--pds-space-1) var(--pds-space-2); color: var(--pds-link); text-decoration: none; border-radius: var(--pds-radius-xs); }
.ps-wiki-drawer__link:hover { background: var(--pds-surface-layer-hover); }
